+    let written = unsafe { write(fds[1], msg.as_ptr().cast(), msg.len()) };
+    assert_eq!(written as usize, msg.len());
+
+    let mut buf = [0u8; 4];
+    let n = unsafe { read(fds[0], buf.as_mut_ptr().cast(), buf.len()) };
+    assert_eq!(n as usize, msg.len());
+    assert_eq!(&buf[..n as usize], msg);
+
+    unsafe { close(fds[0]) };
+    unsafe { close(fds[1]) };
